package uk.ac.ed.ltg.jdm.util;import java.io.File;import java.net.URL;import org.apache.commons.lang.StringUtils;/** * A set of utilities for simplifying the process of locating test input * documents for unit tests. */public class TestUtilities {	/**	 * Returns a File located beside the class file of the class passed to it.	 * This is useful for reading in test data files which are being stored in	 * the file system beside the classes that they test.	 * 	 * @param fileName	 *            the file name	 * @param theClass	 *            the the class	 * 	 * @return the package File	 */	public static File getPackageFile(final Class theClass,			final String fileName) {		return new File(getPackageFilePath(theClass, fileName));	}	/**	 * Returns a file path to a file located beside the class file of the class	 * passed to it. This is useful for reading in test data files which are	 * being stored in the file system beside the classes that they test.	 * 	 * @param fileName	 *            the file name	 * @param theClass	 *            the the class	 * 	 * @return the package file path	 */	public static String getPackageFilePath(final Class theClass,			final String fileName) {		final String packageName = theClass.getPackage().getName();		final String path = StringUtils.replaceChars(packageName, '.',				File.separatorChar)				+ File.separatorChar + fileName;		return theClass.getClassLoader().getResource(path).getPath();	}	/**	 * Returns a file located in classpath. This includes test resources in the	 * /src/test/resources directory in a standard maven configuration.	 * 	 * @param fileName	 *            the file name	 * @param theClass	 *            the the class	 * 	 * @return the package file path	 */	public static File getResourceFile(final Class theClass,			final String fileName) {		final URL url = theClass.getResource("/resource/" + fileName);		assert url != null : "Resource not found with name '/" + fileName + "'";		return new File(url.getFile());	}}